<template>
    <label class="b-24-black" v-html="t('trial.title')"> </label>
    <div v-if="!isOffline">

        <!-- <p class="r-16-gray py-4 px-3" v-html="t('trial.informacion')">
        
    </p>
    <label class="b-24-black"  v-html="t('trial.Planes')"></label> -->

        <ul class="ps-0">
            <li class="list-group-item text-start my-3 b-16-black py-3 mx-4 rounded-3 planes px-1"
                @click="selectedPlan = 'Mensual'" style="cursor: pointer;">
                <div class="ps-5 form-check">
                    <input id="plan-m" class="form-check-input me-4" type="radio" name="plan" value="Mensual"
                        v-model="selectedPlan">
                    <label for="plan-m" class="form-check-label" v-html="t('trial.mensual')"
                        style="cursor: pointer;"></label>
                </div>
            </li>
            <li class="list-group-item text-start my-3 b-16-black py-3 mx-4 rounded-3 planes px-1"
                @click="selectedPlan = 'Semestral'" style="cursor: pointer;">
                <div class="ps-5 form-check">
                    <input id="plan-s" class="form-check-input me-4" type="radio" name="plan" value="Semestral"
                        v-model="selectedPlan">
                    <label for="plan-s" class="form-check-label" v-html="t('trial.semestral')"
                        style="cursor: pointer;"></label>
                </div>
            </li>
            <li class="list-group-item text-start my-3 b-16-black py-3 mx-4 rounded-3 planes px-1"
                @click="selectedPlan = 'Anual'" style="cursor: pointer;">
                <div class="ps-5 form-check">
                    <input id="plan-a" class="form-check-input me-4" type="radio" name="plan" value="Anual"
                        v-model="selectedPlan">
                    <label for="plan-a" class="form-check-label" v-html="t('trial.anual')"
                        style="cursor: pointer;"></label>
                </div>
            </li>
        </ul>

        <div class="d-flex justify-content-center py-4">
            <button type="button" class="btn-black border-0 px-5 py-3 rounded-5" @click="proceedToCheckout"
                :disabled="isLoading">
                <span v-if="isLoading" class="spinner-border spinner-border-sm me-2" role="status"
                    aria-hidden="true"></span>
                <span v-html="t('trial.pagar')"></span>
            </button>
        </div>
        <p v-if="errorMsg" class="text-danger text-center mt-2">{{ errorMsg }}</p>
    </div>


    <div v-if="isOffline" class="offline-message d-flex flex-column align-items-center justify-content-center"
        style="min-height: 60vh;">
        <img src="../assets/btnAngerPulse.png" style="width: 200px; opacity: 0.5;" class="mb-4">
        <label class="b-24-gray text-center mb-3" v-html="t('offline.title')"></label>
        <p class="r-16-gray px-4 text-center" v-html="t('offline.trial')"></p>
        <p class="r-14-gray px-4 text-center mt-3" style="opacity: 0.7;" v-html="t('offline.subtitle')"></p>
    </div>

</template>


<script setup>
import { ref, onMounted, onBeforeUnmount } from 'vue'
import { useI18n } from 'vue-i18n'
import { API_BASE_URL } from '@/config/api'

const { t } = useI18n()
const isOffline = ref(!navigator.onLine)
const selectedPlan = ref('')
const isLoading = ref(false)
const errorMsg = ref('')

async function proceedToCheckout() {
    if (!selectedPlan.value) {
        errorMsg.value = t('trial.selecciona')
        return
    }

    const username = localStorage.getItem("token")
    if (!username) return

    isLoading.value = true
    errorMsg.value = ''

    try {
        const response = await fetch(`${API_BASE_URL}/api/stripe/create-checkout-session`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ planId: selectedPlan.value, username: username })
        })

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`)
        }

        const data = await response.json()
        if (data && data.url) {
            window.location.href = data.url
        } else {
            throw new Error("Invalid response from server.")
        }
    } catch (e) {
        console.error(e)
        errorMsg.value = "An error occurred while connecting to Stripe."
    } finally {
        isLoading.value = false
    }
}

onMounted(() => {
    window.addEventListener('online', updateOnlineStatus)
    window.addEventListener('offline', updateOnlineStatus)
})

function updateOnlineStatus() {
    isOffline.value = !navigator.onLine
}

onBeforeUnmount(() => {
    window.removeEventListener('online', updateOnlineStatus)
    window.removeEventListener('offline', updateOnlineStatus)
})
</script>